  const folder = DriveApp.createFolder('Epictete - Catégories Excel');
  const results = [];
  
  for (const [title, sheets] of Object.entries(allData)) {
    Logger.log('Creating: ' + title);
    const ss = SpreadsheetApp.create(title);
    
    // Move to folder
    const file = DriveApp.getFileById(ss.getId());
    folder.addFile(file);
    DriveApp.getRootFolder().removeFile(file);
    
    const sheetNames = Object.keys(sheets);
    
    // Rename first default sheet
    const firstSheet = ss.getSheets()[0];
    firstSheet.setName(sheetNames[0]);
    if (sheets[sheetNames[0]].length > 0) {
      firstSheet.getRange(1, 1, sheets[sheetNames[0]].length, sheets[sheetNames[0]][0].length || 1)
        .setValues(sheets[sheetNames[0]]);
    }
    
    // Create remaining sheets
    for (let i = 1; i < sheetNames.length; i++) {
      const newSheet = ss.insertSheet(sheetNames[i]);
      const data = sheets[sheetNames[i]];
      if (data.length > 0) {
        // Ensure all rows have same column count
        const maxCols = Math.max(...data.map(r => r.length));
        const paddedData = data.map(r => {
          while (r.length < maxCols) r.push('');
          return r;
        });
        if (maxCols > 0) {
          newSheet.getRange(1, 1, paddedData.length, maxCols).setValues(paddedData);
        }
      }
    }
    
    // Share with service account
    ss.addEditor('epictete@epictete-492501.iam.gserviceaccount.com');
    
    results.push(title + ': ' + ss.getUrl());
    Logger.log('Done: ' + title);
  }
  
  Logger.log('\n=== ALL DONE ===');
  Logger.log('Folder: ' + folder.getUrl());
  results.forEach(r => Logger.log(r));
  
  return results;
